const IMPORT_CHINESE_DATA = [{"id":"ch-grade-语文3仿写-0","name":"语文·3·仿写","type":"语文","items":[{"q":"仿照例句写句子：如果我是阳光，我将照亮所有的黑暗。如果我是( )，我将( )。","a":"（示例）春风；吹绿每一棵小草"}]},{"id":"ch-grade-语文3修辞-1","name":"语文·3·修辞","type":"语文","items":[{"q":"\"月亮像一个害羞的小姑娘，悄悄地躲进了云层里。\"这句话运用了( )的修辞手法。","a":"比喻和拟人"},{"q":"\"燕子去了，有再来的时候；杨柳枯了，有再青的时候；桃花谢了，有再开的时候。\"这句话运用了( )的修辞手法。","a":"排比"}]},{"id":"ch-grade-语文3填空-2","name":"语文·3·填空","type":"语文","items":[{"q":"\"假\"有两个读音，读jiǎ时可以组词( )，读jià时可以组词( )。","a":"真假；放假"},{"q":"写出下列词语的近义词：美丽-( )，快乐-( )，认真-( )。","a":"漂亮；高兴；仔细"},{"q":"写出下列词语的反义词：黑暗-( )，寒冷-( )，落后-( )。","a":"光明；温暖；先进"}]},{"id":"ch-grade-语文3排序-3","name":"语文·3·排序","type":"语文","items":[{"q":"将下列句子排成一段通顺的话：( )小明把乒乓球捡了起来。( )小明不小心把乒乓球踢到了桌子下面。( )小明弯下腰往桌子下面看。( )小明看到了乒乓球。","a":"4-1-2-3"}]},{"id":"ch-grade-语文3改写-4","name":"语文·3·改写","type":"语文","items":[{"q":"把下列句子改成\"把\"字句：小猴子吃掉了香蕉。","a":"小猴子把香蕉吃掉了。"},{"q":"把下列句子改成\"被\"字句：雨水淋湿了我的衣服。","a":"我的衣服被雨水淋湿了。"},{"q":"把下列陈述句改为反问句：这幅画是我们班小明画的。","a":"这幅画难道不是我们班小明画的吗？"},{"q":"扩句：小鸟飞。","a":"（示例）可爱的小鸟在天空中自由自在地飞。"},{"q":"缩句：勤劳的小蜜蜂在花丛中快乐地采蜜。","a":"蜜蜂采蜜。"}]},{"id":"ch-grade-语文3理解-5","name":"语文·3·理解","type":"语文","items":[{"q":"\"霜叶红于二月花\"中的\"于\"是什么意思？这句诗表达了诗人怎样的感情？","a":"\"于\"是\"比\"的意思。表达了诗人对秋天枫叶的喜爱和赞美之情。"},{"q":"《夜书所见》中\"江上秋风动客情\"的\"客情\"指的是什么？","a":"\"客情\"指的是诗人身处异乡，思念家乡的感情。"},{"q":"\"欲把西湖比西子\"运用了什么修辞手法？\"西子\"指的是谁？","a":"比喻。\"西子\"指的是西施，中国古代四大美女之一。"}]},{"id":"ch-grade-语文3看拼音写词语-6","name":"语文·3·看拼音写词语","type":"语文","items":[{"q":"写出拼音对应的词语：jìng lǐ","a":"敬礼"},{"q":"写出拼音对应的词语：hú dié","a":"蝴蝶"},{"q":"写出拼音对应的词语：cū zhuàng","a":"粗壮"},{"q":"写出拼音对应的词语：yǎn zòu","a":"演奏"},{"q":"写出拼音对应的词语：bǎo guì","a":"宝贵"},{"q":"写出拼音对应的词语：yǒng qì","a":"勇气"},{"q":"写出拼音对应的词语：lǚ xíng","a":"旅行"},{"q":"写出拼音对应的词语：wán shuǎ","a":"玩耍"}]},{"id":"ch-grade-语文3选择-7","name":"语文·3·选择","type":"语文","items":[{"q":"\"咬\"字的部首是( )。\nA. 口\nB. 交\nC. 尸\nD. 女","a":"A","options":["A","B","C","D"],"optionTexts":{"A":"口","B":"交","C":"尸","D":"女"}},{"q":"下列词语中，没有错别字的是( )。\nA. 蓝球\nB. 篮天\nC. 蓝色\nD. 篮色","a":"C","options":["A","B","C","D"],"optionTexts":{"A":"蓝球","B":"篮天","C":"蓝色","D":"篮色"}},{"q":"\"兴冲冲\"中\"冲\"的读音是( )。\nA. chōng\nB. chòng\nC. cōng\nD. chōn","a":"A","options":["A","B","C","D"],"optionTexts":{"A":"chōng","B":"chòng","C":"cōng","D":"chōn"}},{"q":"下列词语搭配不当的是( )。\nA. 发扬优点\nB. 发挥作用\nC. 发挥错误\nD. 发扬传统","a":"C","options":["A","B","C","D"],"optionTexts":{"A":"发扬优点","B":"发挥作用","C":"发挥错误","D":"发扬传统"}}]},{"id":"ch-grade-语文3造句-8","name":"语文·3·造句","type":"语文","items":[{"q":"用\"虽然......但是......\"造句。","a":"（示例）虽然天气很冷，但是他依然坚持晨跑。"}]},{"id":"ch-grade-语文3阅读-9","name":"语文·3·阅读","type":"语文","items":[{"q":"短文主要描写了春天的哪些景物？","a":"小草、桃花、柳树、小燕子、鸭子。"},{"q":"\"桃树上开满了粉红色的桃花，远远望去，像一片灿烂的云霞。\"这句话运用了什么修辞手法？把什么比作什么？","a":"比喻。把桃花比作云霞。"},{"q":"\"细长的柳条在微风中轻轻摇摆，像少女的长发。\"这个比喻句中，本体是什么？喻体是什么？","a":"本体是柳条，喻体是少女的长发。"},{"q":"小猫为什么一条鱼也没钓到？","a":"因为小猫三心二意，一会儿捉蜻蜓，一会儿捉蝴蝶，没有专心钓鱼。"},{"q":"这个故事告诉我们什么道理？","a":"做事情要一心一意，不能三心二意。"}]},{"id":"ch-grade-语文3默写-10","name":"语文·3·默写","type":"语文","items":[{"q":"默写《山行》（杜牧）","a":"远上寒山石径斜，白云生处有人家。停车坐爱枫林晚，霜叶红于二月花。"},{"q":"默写《赠刘景文》（苏轼）","a":"荷尽已无擎雨盖，菊残犹有傲霜枝。一年好景君须记，最是橙黄橘绿时。"},{"q":"默写《夜书所见》（叶绍翁）","a":"萧萧梧叶送寒声，江上秋风动客情。知有儿童挑促织，夜深篱落一灯明。"},{"q":"默写《望天门山》（李白）","a":"天门中断楚江开，碧水东流至此回。两岸青山相对出，孤帆一片日边来。"},{"q":"默写《饮湖上初晴后雨》（苏轼）","a":"水光潋滟晴方好，山色空蒙雨亦奇。欲把西湖比西子，淡妆浓抹总相宜。"}]},{"id":"ch-grade-语文4仿写-11","name":"语文·4·仿写","type":"语文","items":[{"q":"仿照例句写排比句：如果你是一棵大树，就撒下一片阴凉；如果你是( )，就( )；如果你是( )，就( )。","a":"（示例）一泓清泉；滋润一方土地；一棵小草；增添一分绿意"}]},{"id":"ch-grade-语文4修改病句-12","name":"语文·4·修改病句","type":"语文","items":[{"q":"修改病句：我断定他可能生病了。","a":"我断定他生病了。（或：他可能生病了。）"},{"q":"修改病句：我们要学习他刻苦钻研认真学习。","a":"我们要学习他刻苦钻研认真学习的精神。（或：我们要学习他刻苦钻研、认真学习。）"}]},{"id":"ch-grade-语文4修辞-13","name":"语文·4·修辞","type":"语文","items":[{"q":"\"这不是伟大的奇观吗？\"运用了什么修辞手法？改为陈述句。","a":"反问。这是伟大的奇观。"}]},{"id":"ch-grade-语文4填空-14","name":"语文·4·填空","type":"语文","items":[{"q":"给\"鲜\"选择正确的读音：新鲜(xiān/xiǎn)，鲜为人知(xiān/xiǎn)","a":"xiān；xiǎn"},{"q":"\"顾\"字在字典中有以下解释：A回头看 B拜访 C注意、照管 D但是。在\"顾名思义\"中\"顾\"的意思是( )，在\"三顾茅庐\"中是( )，在\"奋不顾身\"中是( )。","a":"A；B；C"},{"q":"把下列成语补充完整：眉( )目秀，( )发童颜，明( )皓齿，文质( )( )。","a":"清；鹤；眸；彬彬"}]},{"id":"ch-grade-语文4扩写-15","name":"语文·4·扩写","type":"语文","items":[{"q":"扩写句子：花开了。","a":"（示例）公园里的各种各样的花在温暖的春天里竞相开放了。"}]},{"id":"ch-grade-语文4改写-16","name":"语文·4·改写","type":"语文","items":[{"q":"改成比喻句：月亮升起来了。","a":"（示例）圆圆的月亮像一个银盘似的升起来了。"},{"q":"改成拟人句：春风吹拂着柳枝。","a":"（示例）春风轻轻地抚摸着柳枝。"},{"q":"用关联词合并：我长大了。我小时候很淘气。","a":"虽然我小时候很淘气，但是我现在长大了。"}]},{"id":"ch-grade-语文4标点-17","name":"语文·4·标点","type":"语文","items":[{"q":"给句子加标点：他说 我明天要去北京 你一起去吗","a":"他说：\"我明天要去北京，你一起去吗？\""}]},{"id":"ch-grade-语文4理解-18","name":"语文·4·理解","type":"语文","items":[{"q":"\"不识庐山真面目，只缘身在此山中\"蕴含了什么哲理？","a":"当局者迷，旁观者清。说明了看问题要全面，不能片面。"},{"q":"\"梅须逊雪三分白，雪却输梅一段香\"表达了什么观点？","a":"梅和雪各有所长，各有所短。人也是一样，各有优缺点。"},{"q":"\"但使龙城飞将在，不教胡马度阴山\"中的\"飞将\"指的是谁？表达了诗人怎样的愿望？","a":"\"飞将\"指李广。表达了诗人希望朝廷启用良将，早日平息边塞战事，使人民安居乐业的愿望。"}]},{"id":"ch-grade-语文4看拼音写词语-19","name":"语文·4·看拼音写词语","type":"语文","items":[{"q":"bó wù guǎn","a":"博物馆"},{"q":"hén jì","a":"痕迹"},{"q":"suí yù ér ān","a":"随遇而安"},{"q":"jīng pí lì jié","a":"精疲力竭"},{"q":"téng yún jià wù","a":"腾云驾雾"},{"q":"chóng zhěng qí gǔ","a":"重整旗鼓"}]},{"id":"ch-grade-语文4缩写-20","name":"语文·4·缩写","type":"语文","items":[{"q":"缩写句子：在一间屋子里横七竖八地拉了许多绳子。","a":"屋子里拉了绳子。"}]},{"id":"ch-grade-语文4选择-21","name":"语文·4·选择","type":"语文","items":[{"q":"下列加点字读音全部正确的是( )。\nA. 霎时(chà)\nB. 住宅(zhái)\nC. 弯曲(qū)\nD. 下降(jiàng)","a":"D","options":["A","B","C","D"],"optionTexts":{"A":"霎时(chà)","B":"住宅(zhái)","C":"弯曲(qū)","D":"下降(jiàng)"}},{"q":"\"鼎\"字共有( )画，第六画是( )。\nA. 12 竖\nB. 12 横折\nC. 13 竖折折\nD. 11 竖","a":"A","options":["A","B","C","D"],"optionTexts":{"A":"12 竖","B":"12 横折","C":"13 竖折折","D":"11 竖"}},{"q":"下列词语感情色彩不同类的是( )。\nA. 英勇\nB. 高尚\nC. 慷慨\nD. 懦弱","a":"D","options":["A","B","C","D"],"optionTexts":{"A":"英勇","B":"高尚","C":"慷慨","D":"懦弱"}}]},{"id":"ch-grade-语文4阅读-22","name":"语文·4·阅读","type":"语文","items":[{"q":"蟋蟀建造住宅用了哪些工具？","a":"前足、钳子、后足、后腿上的锯。"},{"q":"从哪些地方可以看出蟋蟀建造住宅很辛苦？","a":"用前足扒土，用钳子搬土块，用后足踏地，用锯推土；累了只休息不大一会儿又继续工作。"},{"q":"\"我一连看了两个钟头，看得有些不耐烦了\"这句话的作用是什么？","a":"反衬出蟋蟀工作有耐心、坚持不懈的精神。"},{"q":"爬山虎的脚长在哪里？是什么样子的？","a":"长在茎上长叶柄的地方的反面。是枝状的六七根细丝，像蜗牛的触角，颜色是嫩红的。"},{"q":"爬山虎是怎样往上爬的？","a":"脚触着墙时，细丝的头上变成小圆片巴住墙，细丝由直变弯，把嫩茎拉一把紧贴在墙上，就这样一脚一脚地往上爬。"},{"q":"\"每根细丝像蜗牛的触角\"运用了什么修辞手法？有什么作用？","a":"比喻。生动形象地写出了爬山虎的脚的形状和细小。"}]},{"id":"ch-grade-语文4默写-23","name":"语文·4·默写","type":"语文","items":[{"q":"默写《暮江吟》（白居易）","a":"一道残阳铺水中，半江瑟瑟半江红。可怜九月初三夜，露似真珠月似弓。"},{"q":"默写《题西林壁》（苏轼）","a":"横看成岭侧成峰，远近高低各不同。不识庐山真面目，只缘身在此山中。"},{"q":"默写《雪梅》（卢钺）","a":"梅雪争春未肯降，骚人阁笔费评章。梅须逊雪三分白，雪却输梅一段香。"},{"q":"默写《出塞》（王昌龄）","a":"秦时明月汉时关，万里长征人未还。但使龙城飞将在，不教胡马度阴山。"},{"q":"默写《夏日绝句》（李清照）","a":"生当作人杰，死亦为鬼雄。至今思项羽，不肯过江东。"}]},{"id":"ch-grade-语文5仿写-24","name":"语文·5·仿写","type":"语文","items":[{"q":"仿照例句，用上加点的词写话：人要做有用的人，不要做只讲体面，而对别人没有好处的人。","a":"（示例）人要做诚实的人，不要做只说空话，而不付诸行动的人。"}]},{"id":"ch-grade-语文5修改病句-25","name":"语文·5·修改病句","type":"语文","items":[{"q":"修改：通过这次活动，使我受到了深刻的教育。","a":"这次活动，使我受到了深刻的教育。（或：通过这次活动，我受到了深刻的教育。）"},{"q":"修改：我国的人口是世界上最多的国家。","a":"我国是世界上人口最多的国家。"}]},{"id":"ch-grade-语文5修辞-26","name":"语文·5·修辞","type":"语文","items":[{"q":"\"桂花开花的时候，香飘十里。\"运用了什么修辞手法？","a":"夸张"},{"q":"\"嗒嗒的声音，像轻快的音乐；清波漾漾，人影绰绰，给人画一般的美感。\"运用了什么修辞手法？","a":"比喻"}]},{"id":"ch-grade-语文5关联词-27","name":"语文·5·关联词","type":"语文","items":[{"q":"在括号里填上合适的关联词：( )花生不好看，( )很有用。","a":"虽然；但是"}]},{"id":"ch-grade-语文5填空-28","name":"语文·5·填空","type":"语文","items":[{"q":"给多音字选择正确读音：方便(biàn/pián)宜，便宜(biàn/pián)货","a":"biàn；pián"},{"q":"\"开辟\"的近义词是( )，反义词是( )。\"完好无损\"的近义词是( )。","a":"开垦；荒废；完整无缺"},{"q":"根据意思写成语：形容声音巨大响亮，像要把耳朵震聋一样。( )","a":"震耳欲聋"},{"q":"根据意思写成语：形容建筑物等异常华丽，光彩夺目。( )","a":"金碧辉煌"}]},{"id":"ch-grade-语文5改写-29","name":"语文·5·改写","type":"语文","items":[{"q":"改成双重否定句：我必须完成作业。","a":"我不得不完成作业。"},{"q":"把直接引语改为间接引语：父亲说：\"对，这是我对你们的希望。\"","a":"父亲说，对，这是他对我们的希望。"}]},{"id":"ch-grade-语文5标点-30","name":"语文·5·标点","type":"语文","items":[{"q":"给下面句子加标点：圆明园不但建筑宏伟 还收藏着最珍贵的历史文物 上自先秦时代的青铜礼器 下至唐 宋 元 明 清历代的名人书画和各种奇珍异宝","a":"圆明园不但建筑宏伟，还收藏着最珍贵的历史文物：上自先秦时代的青铜礼器，下至唐、宋、元、明、清历代的名人书画和各种奇珍异宝。"}]},{"id":"ch-grade-语文5理解-31","name":"语文·5·理解","type":"语文","items":[{"q":"《示儿》中\"但悲不见九州同\"的\"九州\"指的是什么？表达了诗人怎样的感情？","a":"\"九州\"指中国。表达了诗人至死不忘收复失地、渴望祖国统一的强烈爱国之情。"},{"q":"\"明月松间照，清泉石上流\"描绘了怎样的画面？","a":"皎洁的月光透过松林洒落下来，清澈的泉水在山石上缓缓流淌。描绘了一幅清幽明净的山间秋夜图。"},{"q":"\"月落乌啼霜满天\"描绘了怎样的景象？营造了怎样的氛围？","a":"月亮落下，乌鸦啼叫，寒霜满天。营造了凄清、冷寂、愁苦的氛围。"}]},{"id":"ch-grade-语文5看拼音写词语-32","name":"语文·5·看拼音写词语","type":"语文","items":[{"q":"ài mù","a":"爱慕"},{"q":"dīng zhǔ","a":"叮嘱"},{"q":"jǐn shèn","a":"谨慎"},{"q":"qí qū","a":"崎岖"},{"q":"bǎo lěi","a":"堡垒"},{"q":"jīn bì huī huáng","a":"金碧辉煌"}]},{"id":"ch-grade-语文5缩写-33","name":"语文·5·缩写","type":"语文","items":[{"q":"缩写：巍峨的金字塔是世界古代建筑的一个奇迹。","a":"金字塔是奇迹。"}]},{"id":"ch-grade-语文5选择-34","name":"语文·5·选择","type":"语文","items":[{"q":"下列加点字读音有误的是( )。\nA. 强逼(qiǎng)\nB. 划归(huà)\nC. 冠军(guàn)\nD. 削弱(xiāo)","a":"D","options":["A","B","C","D"],"optionTexts":{"A":"强逼(qiǎng)","B":"划归(huà)","C":"冠军(guàn)","D":"削弱(xiāo)"}},{"q":"\"举\"在\"举世闻名\"中的意思是( )。\nA. 抬起\nB. 提出\nC. 全\nD. 举动","a":"C","options":["A","B","C","D"],"optionTexts":{"A":"抬起","B":"提出","C":"全","D":"举动"}},{"q":"下列句子中\"体面\"一词的意思与其他三项不同的是( )。\nA. 他是个体面人\nB. 今天穿得很体面\nC. 这种做法很不体面\nD. 他靠劳动过着体面的生活","a":"B","options":["A","B","C","D"],"optionTexts":{"A":"他是个体面人","B":"今天穿得很体面","C":"这种做法很不体面","D":"他靠劳动过着体面的生活"}}]},{"id":"ch-grade-语文5阅读-35","name":"语文·5·阅读","type":"语文","items":[{"q":"父亲拿花生和什么作比较？突出了花生怎样的品质？","a":"拿花生和桃子、石榴、苹果作比较。突出了花生朴实无华、默默无闻、不计名利的品质。"},{"q":"\"所以你们要像花生，它虽然不好看，可是很有用。\"父亲的这句话有什么深刻含义？","a":"父亲教育子女要做有用的人，不要只追求外表的光鲜，而要注重内在的价值，做对他人和社会有贡献的人。"},{"q":"这段话从哪些方面介绍了圆明园的建筑特点？","a":"从仿照各地名胜建造、根据古代诗人的诗情画意建造、民族建筑和西洋景观等方面介绍。"},{"q":"这段话运用了怎样的修辞手法？有什么作用？","a":"排比。列举了圆明园内的各种建筑，突出了圆明园建筑宏伟、景色壮丽的"},{"q":"作者详细描写圆明园昔日的辉煌，有什么写作目的？","a":"通过对比昔日的辉煌和毁灭后的残破，更能激发读者对祖国灿烂文化的热爱和对侵略者野蛮行径的痛恨。"},{"q":"\"一卷揉得皱皱的毛票\"\"龟裂的手指\"这些细节描写说明了什么？","a":"说明母亲的钱来得不容易，是她省吃俭用、辛勤劳作攒下来的，体现了母亲的艰辛。"},{"q":"\"我挺高兴他爱看书的！\"这句话表现了母亲怎样的品质？","a":"表现了母亲深明大义、尊重孩子兴趣爱好、无私奉献的品质。"},{"q":"四个\"立刻\"连用，运用了什么修辞手法？有什么表达效果？","a":"排比和反复。突出了母亲为养家糊口争分夺秒地辛苦劳作，表现了她勤劳、坚韧的品格。"}]},{"id":"ch-grade-语文5默写-36","name":"语文·5·默写","type":"语文","items":[{"q":"默写《示儿》（陆游）","a":"死去元知万事空，但悲不见九州同。王师北定中原日，家祭无忘告乃翁。"},{"q":"默写《己亥杂诗》（龚自珍）","a":"九州生气恃风雷，万马齐喑究可哀。我劝天公重抖擞，不拘一格降人材。"},{"q":"默写《山居秋暝》（王维）","a":"空山新雨后，天气晚来秋。明月松间照，清泉石上流。竹喧归浣女，莲动下渔舟。随意春芳歇，王孙自可留。"},{"q":"默写《枫桥夜泊》（张继）","a":"月落乌啼霜满天，江枫渔火对愁眠。姑苏城外寒山寺，夜半钟声到客船。"},{"q":"默写《长相思》（纳兰性德）","a":"山一程，水一程，身向榆关那畔行，夜深千帐灯。风一更，雪一更，聒碎乡心梦不成，故园无此声。"}]},{"id":"ch-grade-语文6仿写-37","name":"语文·6·仿写","type":"语文","items":[{"q":"仿照例句：如果你是一滴水，你是否滋润了一寸土地？如果你是一线阳光，你是否( )？如果你是一粒粮食，你是否( )？","a":"照亮了一分黑暗；哺育了有用的生命"}]},{"id":"ch-grade-语文6修改病句-38","name":"语文·6·修改病句","type":"语文","items":[{"q":"修改：读了《狼牙山五壮士》这篇课文，使我深受感动。","a":"读了《狼牙山五壮士》这篇课文，我深受感动。"},{"q":"修改：我们要积极响应\"人人动手，绿化祖国\"。","a":"我们要积极响应\"人人动手，绿化祖国\"的号召。"}]},{"id":"ch-grade-语文6修辞-39","name":"语文·6·修辞","type":"语文","items":[{"q":"\"有的宅院里探出半树银妆，星星般的小花缀满枝头。\"运用了什么修辞手法？","a":"比喻和拟人"},{"q":"\"你想，四周黑洞洞的，还不容易碰壁吗？\"这句话中\"四周黑洞洞的\"指什么？\"碰壁\"指什么？","a":"\"四周黑洞洞的\"指当时社会的黑暗；\"碰壁\"指鲁迅先生在与反动派作斗争时遭受的挫折和迫害。"}]},{"id":"ch-grade-语文6填空-40","name":"语文·6·填空","type":"语文","items":[{"q":"\"系\"字有两个读音：xì和jì。在\"关系\"中读( )，在\"系鞋带\"中读( )。","a":"xì；jì"},{"q":"给\"熬\"选择读音和意思：熬药(áo/āo)，熬白菜(áo/āo)。","a":"áo；āo"},{"q":"写出成语中带点字的意思：德高望( )重，( )的意思是( )。","a":"望：名望、声望"},{"q":"\"张冠李戴\"中的\"冠\"意思是( )，\"囫囵吞枣\"比喻( )。","a":"帽子；读书等不加分析地笼统接受"}]},{"id":"ch-grade-语文6排序-41","name":"语文·6·排序","type":"语文","items":[{"q":"将下列句子排成一段通顺的话：( )我们也在堆雪人。( )雪停了。( )大家扫雪。( )大雪整整下了一夜。( )同学们扫得很快，雪堆成了小山。","a":"5-2-3-1-4"}]},{"id":"ch-grade-语文6改写-42","name":"语文·6·改写","type":"语文","items":[{"q":"改为转述句：总理对我说：\"我今晚上要批这些文件。你们送来的稿子，我放在最后。\"","a":"总理对我说，他今晚上要批那些文件，我们送来的稿子，他放在最后。"},{"q":"改为拟人句：风儿吹过，树叶沙沙作响。","a":"（示例）风儿轻轻走过，树叶便唱起了欢快的歌。"}]},{"id":"ch-grade-语文6标点-43","name":"语文·6·标点","type":"语文","items":[{"q":"给下面句子加标点：我们的共产党和共产党所领导的八路军 新四军 是革命的队伍 我们这个队伍完全是为着解放人民的 是彻底地为人民的利益工作的","a":"我们的共产党和共产党所领导的八路军、新四军，是革命的队伍。我们这个队伍完全是为着解放人民的，是彻底地为人民的利益工作的。"}]},{"id":"ch-grade-语文6理解-44","name":"语文·6·理解","type":"语文","items":[{"q":"《宿建德江》中\"野旷天低树，江清月近人\"描绘了怎样的画面？表达了诗人怎样的感情？","a":"原野空旷，远处的天空比树还低；江水清澈，水中的月影仿佛与人更亲近。表达了诗人孤独寂寞、思念家乡的愁绪。"},{"q":"\"明月别枝惊鹊，清风半夜鸣蝉\"中\"惊\"和\"鸣\"是否矛盾？为什么？","a":"不矛盾。\"惊\"写鹊儿因明月升起被惊醒而飞离枝头，\"鸣\"写蝉在清风中歌唱。以动衬静，写出了乡村夏夜的宁静美好。"},{"q":"\"五岭逶迤腾细浪，乌蒙磅礴走泥丸\"运用了什么修辞手法？表现了红军怎样的精神？","a":"比喻和夸张。把绵延的五岭比作细浪，把磅礴的乌蒙比作泥丸。表现了红军不畏艰难、乐观豪迈的革命精神。"},{"q":"\"儿童相见不相识，笑问客从何处来\"表达了诗人怎样的心情？","a":"表达了诗人久别回乡，物是人非的感慨和岁月流逝的怅惘。"}]},{"id":"ch-grade-语文6看拼音写词语-45","name":"语文·6·看拼音写词语","type":"语文","items":[{"q":"cāng máng","a":"苍茫"},{"q":"yōu yǎ","a":"优雅"},{"q":"bào yuàn","a":"抱怨"},{"q":"dǎo méi","a":"倒霉"},{"q":"kāng kǎi","a":"慷慨"},{"q":"pái shān dǎo hǎi","a":"排山倒海"}]},{"id":"ch-grade-语文6缩写-46","name":"语文·6·缩写","type":"语文","items":[{"q":"缩写：毛主席在群众一阵又一阵的掌声中宣读中央人民政府的公告。","a":"毛主席宣读公告。"}]},{"id":"ch-grade-语文6选择-47","name":"语文·6·选择","type":"语文","items":[{"q":"下列加点字注音全部正确的一项是( )。\nA. 蜷缩(juǎn)\nB. 勉强(qiáng)\nC. 友谊(yì)\nD. 抡起(lūn)","a":"C","options":["A","B","C","D"],"optionTexts":{"A":"蜷缩(juǎn)","B":"勉强(qiáng)","C":"友谊(yì)","D":"抡起(lūn)"}},{"q":"下列词语书写全部正确的是( )。\nA. 悬涯峭壁\nB. 悬崖峭壁\nC. 悬涯俏壁\nD. 玄崖峭壁","a":"B","options":["A","B","C","D"],"optionTexts":{"A":"悬涯峭壁","B":"悬崖峭壁","C":"悬涯俏壁","D":"玄崖峭壁"}},{"q":"\"全场就响起了一阵轰雷似的掌声。\"\"轰雷\"在句中指的是( )。\nA. 真的打雷\nB. 掌声非常大\nC. 雷声像掌声\nD. 全场很安静","a":"B","options":["A","B","C","D"],"optionTexts":{"A":"真的打雷","B":"掌声非常大","C":"雷声像掌声","D":"全场很安静"}}]},{"id":"ch-grade-语文6阅读-48","name":"语文·6·阅读","type":"语文","items":[{"q":"\"在天底下，一碧千里，而并不茫茫\"中\"一碧千里\"是什么意思？为什么说\"并不茫茫\"？","a":"\"一碧千里\"指一片碧绿，十分广阔。因为草原虽然辽阔，但四面都有小丘，羊群在上面活动，景色富有变化，所以并不显得空旷迷茫。"},{"q":"\"羊群一会儿上了小丘，一会儿又下来，走在哪里都像给无边的绿毯绣上了白色的大花。\"运用了什么修辞手法？有什么表达效果？","a":"比喻。把草原比作无边的绿毯，把羊群比作白色的大花。生动形象地写出了草原的碧绿辽阔和羊群的洁白美丽。"},{"q":"\"到处翠色欲流，轻轻流入云际\"中\"翠色欲流\"是什么意思？","a":"翠绿的颜色浓得好像要流淌下来一样，形容绿到了极致。"},{"q":"\"我素不知道天下有这许多新鲜事\"中\"素\"是什么意思？说明了什么？","a":"\"素\"是\"向来、一直\"的意思。说明\"我\"之前生活的狭窄和知识的贫乏。"},{"q":"\"他们都和我一样只看见院子里高墙上的四角的天空\"这句话有什么深刻含义？","a":"比喻\"我\"和往常的朋友们生活天地狭窄，像井底之蛙一样孤陋寡闻，反衬出闰土见多识广。"},{"q":"短文表达了作者怎样的思想感情？","a":"表达了作者对闰土见多识广的羡慕和钦佩，对自己所处环境的不满，对自由广阔生活的向往。"},{"q":"\"你想，四周黑洞洞的，还不容易碰壁吗？\"伯父这句话有什么深刻含义？","a":"\"四周黑洞洞的\"比喻当时社会的黑暗；\"碰壁\"比喻与反动势力作斗争时遭受的迫害和挫折。表现了鲁迅先生对黑暗社会的抨击和革命乐观主义精神。"},{"q":"\"我恍然大悟\"，\"我\"真的\"恍然大悟\"了吗？为什么？","a":"没有。\"我\"年纪小，没有听懂伯父话中的深意，只是从字面上理解，以为伯父真的是走路不小心碰扁了鼻子。"},{"q":"短文中哪些地方体现了鲁迅先生\"为别人想得多，为自己想得少\"的品质？","a":"伯父用幽默的方式谈论自己遭受的迫害，不把自己的伤痛放在心上，体现了为自己想得少；他关心下一代的成长，用风趣的语言教育孩子，体现了为别人想得多。"}]},{"id":"ch-grade-语文6默写-49","name":"语文·6·默写","type":"语文","items":[{"q":"默写《宿建德江》（孟浩然）","a":"移舟泊烟渚，日暮客愁新。野旷天低树，江清月近人。"},{"q":"默写《西江月·夜行黄沙道中》（辛弃疾）","a":"明月别枝惊鹊，清风半夜鸣蝉。稻花香里说丰年，听取蛙声一片。七八个星天外，两三点雨山前。旧时茅店社林边，路转溪桥忽见。"},{"q":"默写《七律·长征》（毛泽东）","a":"红军不怕远征难，万水千山只等闲。五岭逶迤腾细浪，乌蒙磅礴走泥丸。金沙水拍云崖暖，大渡桥横铁索寒。更喜岷山千里雪，三军过后尽开颜。"},{"q":"默写《春日》（朱熹）","a":"胜日寻芳泗水滨，无边光景一时新。等闲识得东风面，万紫千红总是春。"},{"q":"默写《回乡偶书》（贺知章）","a":"少小离家老大回，乡音无改鬓毛衰。儿童相见不相识，笑问客从何处来。"},{"q":"默写《浪淘沙》（刘禹锡）","a":"九曲黄河万里沙，浪淘风簸自天涯。如今直上银河去，同到牵牛织女家。"}]}];
